@Service
class CommentService {
    @Autowired
    private CommentRepository commentRepository;
    
    private static final List<String> ALLOWED_TAGS = List.of("b", "i", "u", "em", "strong", "p", "br");
    
    public List<CommentDTO> getAllComments() {
        List<Comment> comments = commentRepository.findAllByOrderByCreatedAtDesc();
        return comments.stream()
                .map(comment -> new CommentDTO(comment, sanitizeHtml(comment.getContent())))
                .collect(Collectors.toList());
    }
    
    public Comment saveComment(String username, String content) {
        String escapedUsername = HtmlUtils.htmlEscape(username);
        Comment comment = new Comment(escapedUsername, content);
        return commentRepository.save(comment);
    }
    
    public String sanitizeHtml(String input) {
        if (input == null || input.isEmpty()) {
            return "";
        }
        
        String escaped = HtmlUtils.htmlEscape(input);
        
        for (String tag : ALLOWED_TAGS) {
            escaped = escaped.replace("&lt;" + tag + "&gt;", "<" + tag + ">");
            escaped = escaped.replace("&lt;/" + tag + "&gt;", "</" + tag + ">");
            escaped = escaped.replace("&lt;" + tag + " /&gt;", "<" + tag + " />");
            escaped = escaped.replace("&lt;" + tag + "/&gt;", "<" + tag + "/>");
        }
        
        return escaped;
    }
}

@Controller
public class CommentController {
    
    @Autowired
    private CommentService commentService;
    
    @GetMapping("/comments")
    public String showComments(Model model) {
        List<CommentDTO> comments = commentService.getAllComments();
        model.addAttribute("comments", comments);
        return "comments";
    }
    
    @PostMapping("/comments")
    public String addComment(@RequestParam("username") String username, 
                           @RequestParam("content") String content) {
        commentService.saveComment(username, content);
        return "redirect:/comments";
    }
}